@* Reusable message input: textarea + send/reply button *@

<div class="message-input">
    <textarea @bind="Text"
              @bind:event="oninput"
              @onkeydown="HandleKeyDown"
              placeholder="@Placeholder"
              rows="2"></textarea>
    <button class="btn-send" @onclick="HandleSend" disabled="@string.IsNullOrWhiteSpace(Text)">
        @ButtonLabel
    </button>
</div>

@code {
    [Parameter] public string Placeholder { get; set; } = "Type a message…";
    [Parameter] public string ButtonLabel { get; set; } = "Send";
    [Parameter] public EventCallback<string> OnSend { get; set; }

    private string Text { get; set; } = string.Empty;

    private async Task HandleSend()
    {
        if (string.IsNullOrWhiteSpace(Text)) return;
        var message = Text.Trim();
        Text = string.Empty;
        await OnSend.InvokeAsync(message);
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await HandleSend();
        }
    }
}

.message-input {
    display: flex;
    gap: 8px;
    padding: 12px 16px;
    border-top: 1px solid #e0e0e0;
    background: #fff;
}

.message-input textarea {
    flex: 1;
    resize: none;
    border: 1px solid #ccc;
    border-radius: 6px;
    padding: 8px 12px;
    font-size: 14px;
    font-family: inherit;
    outline: none;
    transition: border-color 0.15s;
}

.message-input textarea:focus {
    border-color: #4a6cf7;
}

.message-input .btn-send {
    align-self: flex-end;
    padding: 8px 20px;
    background: #4a6cf7;
    color: #fff;
    border: none;
    border-radius: 6px;
    font-size: 14px;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.15s;
}

.message-input .btn-send:hover:not(:disabled) {
    background: #3b5de7;
}

.message-input .btn-send:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

@using sv_aad0475353094c028990eb8b1726a1f8.Services

<div class="message-item @(IsHovered ? "hovered" : "")"
     @onmouseenter="() => IsHovered = true"
     @onmouseleave="() => IsHovered = false">

    <div class="message-header">
        <span class="author">@Message.Author</span>
        <span class="timestamp" title="@Message.SentAt.ToString("g")">@FormatRelativeTime(Message.SentAt)</span>
    </div>

    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reactions">
            @foreach (var reaction in Message.Reactions)
            {
                <button class="reaction-badge" @onclick="() => OnReact.InvokeAsync(reaction.Emoji)"
                        title="@string.Join(", ", reaction.Users)">
                    @reaction.Emoji @reaction.Users.Count
                </button>
            }
        </div>
    }

    @if (ReplyCount > 0)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync()">
            @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (IsHovered)
    {
        <div class="action-bar">
            <button class="action-btn" @onclick="() => OnOpenThread.InvokeAsync()" title="Reply in thread">💬</button>
            <button class="action-btn" @onclick="ToggleEmojiPicker" title="Add reaction">😀</button>
        </div>
    }

    @if (ShowEmojiPicker)
    {
        <div class="emoji-picker">
            @foreach (var emoji in CommonEmojis)
            {
                <button class="emoji-option" @onclick="() => PickEmoji(emoji)">@emoji</button>
            }
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public int ReplyCount { get; set; }
    [Parameter] public EventCallback OnOpenThread { get; set; }
    [Parameter] public EventCallback<string> OnReact { get; set; }

    private bool IsHovered { get; set; }
    private bool ShowEmojiPicker { get; set; }

    private static readonly string[] CommonEmojis = ["👍", "❤️", "😂", "🎉", "🤔", "👀"];

    private void ToggleEmojiPicker() => ShowEmojiPicker = !ShowEmojiPicker;

    private async Task PickEmoji(string emoji)
    {
        ShowEmojiPicker = false;
        await OnReact.InvokeAsync(emoji);
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }
}

.message-item {
    position: relative;
    padding: 8px 16px;
    transition: background 0.1s;
}

.message-item.hovered {
    background: #f5f6fa;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.message-header .author {
    font-weight: 700;
    font-size: 14px;
    color: #1a1a2e;
}

.message-header .timestamp {
    font-size: 12px;
    color: #8e8ea0;
}

.message-content {
    font-size: 14px;
    line-height: 1.5;
    color: #2c2c3a;
    white-space: pre-wrap;
    word-break: break-word;
}

.reactions {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    padding: 2px 8px;
    border: 1px solid #ddd;
    border-radius: 12px;
    background: #f0f0f5;
    font-size: 13px;
    cursor: pointer;
    transition: background 0.1s;
}

.reaction-badge:hover {
    background: #e0e0f0;
}

.thread-link {
    display: inline-block;
    margin-top: 4px;
    padding: 0;
    border: none;
    background: none;
    color: #4a6cf7;
    font-size: 13px;
    font-weight: 600;
    cursor: pointer;
}

.thread-link:hover {
    text-decoration: underline;
}

.action-bar {
    position: absolute;
    top: 4px;
    right: 12px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 6px;
    box-shadow: 0 1px 4px rgba(0,0,0,0.08);
    padding: 2px;
}

.action-btn {
    border: none;
