toolArgs.file_text:
.message-item {
    position: relative;
    padding: 8px 16px;
    transition: background 0.1s;
}

.message-item.hovered {
    background: #f5f6fa;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.message-header .author {
    font-weight: 700;
    font-size: 14px;
    color: #1a1a2e;
}

.message-header .timestamp {
    font-size: 12px;
    color: #8e8ea0;
}

.message-content {
    font-size: 14px;
    line-height: 1.5;
    color: #2c2c3a;
    white-space: pre-wrap;
    word-break: break-word;
}

.reactions {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    padding: 2px 8px;
    border: 1px solid #ddd;
    border-radius: 12px;
    background: #f0f0f5;
    font-size: 13px;
    cursor: pointer;
    transition: background 0.1s;
}

.reaction-badge:hover {
    background: #e0e0f0;
}

.thread-link {
    display: inline-block;
    margin-top: 4px;
    padding: 0;
    border: none;
    background: none;
    color: #4a6cf7;
    font-size: 13px;
    font-weight: 600;
    cursor: pointer;
}

.thread-link:hover {
    text-decoration: underline;
}

.action-bar {
    position: absolute;
    top: 4px;
    right: 12px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 6px;
    box-shadow: 0 1px 4px rgba(0,0,0,0.08);
    padding: 2px;
}

.action-btn {
    border: none;
    background: none;
    padding: 4px 8px;
    font-size: 16px;
    cursor: pointer;
    border-radius: 4px;
    transition: background 0.1s;
}

.action-btn:hover {
    background: #f0f0f5;
}

.emoji-picker {
    display: flex;
    gap: 4px;
    margin-top: 4px;
    padding: 6px;
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    box-shadow: 0 2px 8px rgba(0,0,0,0.1);
    width: fit-content;
}

.emoji-option {
    border: none;
    background: none;
    font-size: 20px;
    padding: 4px;
    cursor: pointer;
    border-radius: 4px;
    transition: background 0.1s;
}

.emoji-option:hover {
    background: #f0f0f5;
}

