arguments.file_text:
@using sv_aad0475353094c028990eb8b1726a1f8.Services

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h3>Channels</h3>
    </div>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == ActiveChannelId"
                         OnSelect="() => OnChannelSelected.InvokeAsync(channel.Id)" />
        }
    </div>
</div>

@code {
    [Parameter] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int? ActiveChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }
}

.channel-sidebar {
    display: flex;
    flex-direction: column;
    width: 100%;
    height: 100%;
    background: #1e1f2b;
    color: #e0e0ec;
}

.sidebar-header {
    padding: 16px;
    border-bottom: 1px solid #2a2d3a;
}

.sidebar-header h3 {
    margin: 0;
    font-size: 16px;
    font-weight: 700;
    color: #fff;
}

.channel-list {
    flex: 1;
    overflow-y: auto;
}

@using sv_aad0475353094c028990eb8b1726a1f8.Services

<div class="message-area">
    @if (Channel is not null)
    {
        <div class="area-header">
            <h2># @Channel.Name</h2>
            <p>@Channel.Description</p>
        </div>

        <div class="message-list" @onscroll="HandleScroll" @ref="messageListRef">
            @if (IsLoadingMore)
            {
                <div class="loading-indicator">Loading older messages…</div>
            }
            @foreach (var msg in Messages)
            {
                <MessageItem Message="msg"
                             ReplyCount="GetReplyCount(msg.Id)"
                             OnOpenThread="() => OnOpenThread.InvokeAsync(msg.Id)"
                             OnReact="(emoji) => OnReact.InvokeAsync((msg.Id, emoji))" />
            }
        </div>

        <MessageInput Placeholder="@($"Message #{Channel.Name}")"
                      ButtonLabel="Send"
                      OnSend="HandleSend" />
    }
    else
    {
        <div class="empty-state">
            <p>Select a channel to start chatting</p>
        </div>
    }
</div>

@code {
    [Parameter] public Channel? Channel { get; set; }
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    private ElementReference messageListRef;

    private int GetReplyCount(int messageId) =>
        ThreadSummaries.TryGetValue(messageId, out var summary) ? summary.ReplyCount : 0;

    private async Task HandleSend(string content) =>
        await OnSendMessage.InvokeAsync(content);

    private async Task HandleScroll()
    {
        // Scroll-to-top triggers loading more messages.
        // JS interop would be ideal for precise scroll position detection,
        // but we keep this simple by firing the event and letting the parent debounce.
        await OnLoadMore.InvokeAsync();
    }
}

.message-area {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #fff;
}

.area-header {
    padding: 12px 20px;
    border-bottom: 1px solid #e0e0e0;
    flex-shrink: 0;
}

.area-header h2 {
    margin: 0;
    font-size: 18px;
    font-weight: 700;
    color: #1a1a2e;
}

.area-header p {
    margin: 2px 0 0;
    font-size: 13px;
    color: #8e8ea0;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.loading-indicator {
    text-align: center;
    padding: 12px;
    color: #8e8ea0;
    font-size: 13px;
}

.empty-state {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #8e8ea0;
    font-size: 16px;
}

@using sv_aad0475353094c028990eb8b1726a1f8.Services

<div class="thread-panel">
    <div class="thread-header">
        <h3>Thread</h3>
        <button class="close-btn" @onclick="() => OnClose.InvokeAsync()" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root">
            <MessageItem Message="RootMessage" ReplyCount="0" />
        </div>

        <div class="thread-replies">
            @foreach (var reply in Replies)
            {
                <MessageItem Message="reply" ReplyCount="0" />
            }
        </div>

        <MessageInput Placeholder="Reply…"
                      ButtonLabel="Reply"
                      OnSend="HandleReply" />
    }
</div>

@code {
    [Parameter, EditorRequired] public Message RootMessage { get; set; } = default!;
    [Parameter] public List<Message> Replies { get; set; } = [];
    [Parameter] public EventCallback<string> OnReply { get; set; }
    [Parameter] public EventCallback OnClose { get; set; }

    private async Task HandleReply(string content) =>
        await OnReply.InvokeAsync(content);
}

.thread-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #fafafd;
    border-left: 1px solid #e0e0e0;
}

.thread-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
    flex-shrink: 0;
}

.thread-header h3 {
    margin: 0;
    font-size: 16px;
    font-weight: 700;
    color: #1a1a2e;
}

.close-btn {
    border: none;
    background: none;
    font-size: 18px;
    color: #8e8ea0;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    transition: background 0.1s;
}

.close-btn:hover {
    background: #e8e8f0;
    color: #1a1a2e;
}

.thread-root {
    padding: 8px 0;
    border-bottom: 1px solid #e0e0e0;
    background: #f0f0f5;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

