arguments.file_text:
@page "/chat"
@layout ChatLayout
@using sv_aad0475353094c028990eb8b1726a1f8.Services
@inject IChatService ChatService
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-page">
    <div class="panel-sidebar">
        <ChannelSidebar Channels="channels"
                        ActiveChannelId="selectedChannelId"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="panel-main @(threadRootMessage is null ? "expanded" : "")">
        <MessageArea Channel="selectedChannel"
                     Messages="messages"
                     ThreadSummaries="threadSummaries"
                     IsLoadingMore="isLoadingMore"
                     OnSendMessage="SendMessage"
                     OnOpenThread="OpenThread"
                     OnReact="HandleReaction"
                     OnLoadMore="LoadMoreMessages" />
    </div>

    @if (threadRootMessage is not null)
    {
        <div class="panel-thread">
            <ThreadPanel RootMessage="threadRootMessage"
                         Replies="threadReplies"
                         OnReply="SendThreadReply"
                         OnClose="CloseThread" />
        </div>
    }
</div>

@code {
    private List<Channel> channels = [];
    private List<Message> messages = [];
    private Dictionary<int, ThreadSummary> threadSummaries = [];
    private List<Message> threadReplies = [];

    private Channel? selectedChannel;
    private int? selectedChannelId;
    private Message? threadRootMessage;

    private bool isLoadingMore;
    private bool hasMoreMessages = true;
    private const int PageSize = 30;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();

        if (channels.Count > 0)
        {
            await SelectChannel(channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        selectedChannelId = channelId;
        selectedChannel = channels.Find(c => c.Id == channelId);
        messages = [];
        threadRootMessage = null;
        threadReplies = [];
        hasMoreMessages = true;

        var loaded = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        messages = loaded;
        hasMoreMessages = loaded.Count == PageSize;

        await ChatService.MarkChannelReadAsync(channelId);
        await BuildThreadSummaries();
    }

    private async Task SendMessage(string content)
    {
        if (selectedChannelId is null) return;
        var msg = await ChatService.SendMessageAsync(selectedChannelId.Value, content, null);
        messages.Add(msg);
    }

    private async Task OpenThread(int messageId)
    {
        threadRootMessage = messages.Find(m => m.Id == messageId);
        if (threadRootMessage is null) return;
        threadReplies = await ChatService.GetThreadAsync(messageId);
    }

    private void CloseThread()
    {
        threadRootMessage = null;
        threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (selectedChannelId is null || threadRootMessage is null) return;

        var reply = await ChatService.SendMessageAsync(
            selectedChannelId.Value, content, threadRootMessage.Id);
        threadReplies.Add(reply);

        // Update thread summary count
        if (threadSummaries.TryGetValue(threadRootMessage.Id, out var existing))
        {
            threadSummaries[threadRootMessage.Id] = existing with
            {
                ReplyCount = existing.ReplyCount + 1,
                LastReplyAt = reply.SentAt
            };
        }
        else
        {
            threadSummaries[threadRootMessage.Id] = new ThreadSummary(
                threadRootMessage.Id, 1, reply.SentAt);
        }
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Optimistically update the local message reactions
        var msg = messages.Find(m => m.Id == args.MessageId);
        if (msg is not null)
        {
            var reaction = msg.Reactions.Find(r => r.Emoji == args.Emoji);
            if (reaction is not null)
            {
                reaction.Users.Add("You");
            }
            else
            {
                msg.Reactions.Add(new Reaction(args.Emoji, ["You"]));
            }
        }
    }

    private async Task LoadMoreMessages()
    {
        if (isLoadingMore || !hasMoreMessages || selectedChannelId is null) return;

        isLoadingMore = true;
        var older = await ChatService.GetMessagesAsync(
            selectedChannelId.Value, messages.Count, PageSize);
        hasMoreMessages = older.Count == PageSize;
        messages.InsertRange(0, older);
        isLoadingMore = false;

        await BuildThreadSummaries();
    }

    private async Task BuildThreadSummaries()
    {
        // Build summaries from messages that are thread roots (have replies referencing them)
        var rootIds = messages
            .Where(m => m.ReplyToId is null)
            .Select(m => m.Id)
            .ToHashSet();

        foreach (var rootId in rootIds)
        {
            if (!threadSummaries.ContainsKey(rootId))
            {
                var thread = await ChatService.GetThreadAsync(rootId);
                if (thread.Count > 0)
                {
                    threadSummaries[rootId] = new ThreadSummary(
                        rootId, thread.Count, thread[^1].SentAt);
                }
            }
        }
    }
}

.chat-page {
    display: flex;
    height: 100vh;
    width: 100vw;
    overflow: hidden;
}

.panel-sidebar {
    width: 20%;
    min-width: 220px;
    max-width: 300px;
    flex-shrink: 0;
}

.panel-main {
    flex: 1;
    min-width: 0;
}

.panel-main.expanded {
    flex: 1;
}

.panel-thread {
    width: 25%;
    min-width: 280px;
    max-width: 400px;
    flex-shrink: 0;
}

